mapper.select:
SELECT u.id, u.username, u.real_name, u.avatar_url, u.email, u.phone, u.gender, u.role_type, u.status, u.dept_id, d.name AS dept_name, u.last_login_at, u.created_at, u.updated_at FROM `user` u LEFT JOIN department d ON u.dept_id = d.id
u.deleted_at IS NULL
AND (u.username LIKE CONCAT('%', #{keyword}, '%') OR u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%'))
AND u.status = #{status}
AND u.role_type = #{roleType}
ORDER BY u.created_at DESC
